print(len(pincodes))
start_date = date(2025, 6, 1)       # Start of monsoon season
num_days = 90

data = []

# 2. Generate Base Daily Data
for pincode in pincodes:
    for day in range(num_days):
        current_date = start_date + timedelta(days=day)
        
        # Simulate Weather (Monsoon season: high temp, high humidity)
        temp = np.random.normal(30, 2) 
        humidity = np.random.normal(80, 5)
        rainfall = np.random.exponential(10) if np.random.rand() > 0.5 else 0
        
        # Simulate Baseline Symptom Clusters (Daily counts)
        gastro_symptoms = int(np.random.poisson(5))
        respiratory_symptoms = int(np.random.poisson(10))
        vector_borne_symptoms = int(np.random.poisson(3)) # Baseline is low
        
        # INJECT AN OUTBREAK: Let's make pincode 632014 have a Dengue outbreak in August
        if pincode == 632014 and current_date.month == 8:
            # Symptoms spike aggressively
            vector_borne_symptoms += int(np.random.poisson(25)) 
            target_outbreak = 1 # 1 = Outbreak, 0 = Normal
        else:
            target_outbreak = 0
            
        data.append([
            current_date, pincode, temp, humidity, rainfall, 
            gastro_symptoms, respiratory_symptoms, vector_borne_symptoms, target_outbreak
        ])

# 3. Create DataFrame
df = pd.DataFrame(data, columns=[
    'date', 'pincode', 'temp_c', 'humidity_pct', 'rainfall_mm',
    'cluster_gastro', 'cluster_respiratory', 'cluster_vector_borne', 'is_outbreak'
])

# 4. Feature Engineering: Calculate Rolling Lags (The secret sauce for the AI)
df = df.sort_values(by=['pincode', 'date'])

# Calculate 3-day and 7-day rolling sums for vector-borne symptoms
df['vector_borne_3d_lag'] = df.groupby('pincode')['cluster_vector_borne'].transform(lambda x: x.rolling(window=3, min_periods=1).sum())
df['vector_borne_7d_lag'] = df.groupby('pincode')['cluster_vector_borne'].transform(lambda x: x.rolling(window=7, min_periods=1).sum())

# Fill any NaN values with 0
df = df.fillna(0)

print(df.head(15))
df.to_csv('ayush_synthetic_outbreak_data.csv', index=False)